  1	import React, { FC } from 'react';
  2	import * as _ from 'lodash';
  3	
  4	import { NamespaceModel, RouteModel } from '@kubevirt-ui/kubevirt-api/console';
  5	import {
  6	  getGroupVersionKindForModel,
  7	  ResourceLink,
  8	  Timestamp,
  9	  useAccessReview,
 10	  useAnnotationsModal,
 11	  useLabelsModal,
 12	} from '@openshift-console/dynamic-plugin-sdk';
 13	import { Button } from '@patternfly/react-core';
 14	import { PencilAltIcon } from '@patternfly/react-icons';
 15	import { DetailsItem } from '@utils/components/DetailsItem/DetailsItem';
 16	import { LabelList } from '@utils/components/DetailsItem/LabelList';
 17	import { OwnerReferences } from '@utils/components/OwnerReference/owner-references';
 18	import { useNetworkingTranslation } from '@utils/hooks/useNetworkingTranslation';
 19	import {
 20	  getAnnotations,
 21	  getCreationTimestamp,
 22	  getLabels,
 23	  getName,
 24	  getNamespace,
 25	  getUID,
 26	} from '@utils/resources/shared';
 27	import { RouteKind } from '@utils/types';
 28	
 29	type DetailsSectionLeftColumnProps = { route: RouteKind };
 30	
 31	const DetailsSectionLeftColumn: FC<DetailsSectionLeftColumnProps> = ({ route }) => {
 32	  const { t } = useNetworkingTranslation();
 33	
 34	  const name = getName(route);
 35	  const namespace = getNamespace(route);
 36	
 37	  const annotationsModalLauncher = useAnnotationsModal(route);
 38	  const labelsModalLauncher = useLabelsModal(route);
 39	  const [canUpdate] = useAccessReview({
 40	    group: RouteModel.apiGroup,
 41	    name,
 42	    namespace,
 43	    resource: RouteModel.plural,
 44	    verb: 'patch',
 45	  });
 46	
 47	  return (
 48	    <div className="col-sm-6">
 49	      <dl className="co-m-pane__details" data-test-id="resource-summary">
 50	        <DetailsItem label={t('Name')} obj={route} path={'metadata.name'} />
 51	        {namespace && (
 52	          <DetailsItem label={t('Namespace')} obj={route} path="metadata.namespace">
 53	            <ResourceLink
 54	              groupVersionKind={getGroupVersionKindForModel(NamespaceModel)}
 55	              name={namespace}
 56	              namespace={null}
 57	              title={getUID(route)}
 58	            />
 59	          </DetailsItem>
 60	        )}
 61	        <DetailsItem
 62	          canEdit={canUpdate}
 63	          editAsGroup
 64	          label={t('Labels')}
 65	          obj={route}
 66	          onEdit={labelsModalLauncher}
 67	          path="metadata.labels"
 68	          valueClassName="details-item__value--labels"
 69	        >
 70	          <LabelList
 71	            groupVersionKind={getGroupVersionKindForModel(RouteModel)}
 72	            labels={getLabels(route)}
 73	          />
 74	        </DetailsItem>
 75	        <DetailsItem label={t('Annotations')} obj={route} path="metadata.annotations">
 76	          {canUpdate ? (
 77	            <Button
 78	              data-test="edit-annotations"
 79	              isInline
 80	              onClick={annotationsModalLauncher}
 81	              type="button"
 82	              variant="link"
 83	            >
 84	              {t('{{count}} annotation', { count: _.size(getAnnotations(route, {})) })}
 85	              <PencilAltIcon className="co-icon-space-l pf-v6-c-button-icon--plain" />
 86	            </Button>
 87	          ) : (
 88	            t('{{count}} annotation', { count: _.size(getAnnotations(route, {})) })
 89	          )}
 90	        </DetailsItem>
 91	        <DetailsItem label={t('Service')} obj={route} path="spec.to.name">
 92	          <ResourceLink
 93	            kind={route.spec.to.kind}
 94	            name={route.spec.to.name}
 95	            namespace={namespace}
 96	            title={route.spec.to.name}
 97	          />
 98	        </DetailsItem>
 99	        <DetailsItem label={t('Target port')} obj={route} path="spec.port.targetPort" />
100	        <DetailsItem label={t('Created at')} obj={route} path="metadata.creationTimestamp">
101	          <Timestamp timestamp={getCreationTimestamp(route)} />
102	        </DetailsItem>
103	        <DetailsItem label={t('Owner')} obj={route} path="metadata.ownerReferences">
104	          <OwnerReferences resource={route} />
105	        </DetailsItem>
106	      </dl>
107	    </div>
108	  );
109	};
110	
111	export default DetailsSectionLeftColumn;

